// Optimized pattern generator returning a Number for base-3 representation
function getPatternFast(guessJamos, answerJamos) {
    let pattern = 0;
    let ansUsed = 0;
    let guessUsed = 0;
    const n = guessJamos.length;

    for (let i = 0; i < n; i++) {
        if (guessJamos[i] === answerJamos[i]) {
            pattern += 2 * Math.pow(3, i);
            ansUsed |= (1 << i);
            guessUsed |= (1 << i);
        }
    }

    for (let i = 0; i < n; i++) {
        if ((guessUsed & (1 << i)) === 0) {
            for (let j = 0; j < n; j++) {
                if ((ansUsed & (1 << j)) === 0 && guessJamos[i] === answerJamos[j]) {
                    pattern += 1 * Math.pow(3, i);
                    ansUsed |= (1 << j);
                    break;
                }
            }
        }
    }
    return pattern;
}

let ALL_VALID_WORDS = null;

function initValidWords(jamoLen) {
    if (ALL_VALID_WORDS && ALL_VALID_WORDS.jamoLen === jamoLen) return ALL_VALID_WORDS.words;
    
    let words = [];
    for (let i = 0; i < ALL_WORDS.length; i++) {
        let word = ALL_WORDS[i];
        let jamos = decomposeKoreanWord(word);
        if (jamos.length === jamoLen) {
            // 단어의 규칙 모드 제한: 5자모는 2글자, 7자모는 3글자
            
            
            words.push({ word, jamos });
        }
    }
    ALL_VALID_WORDS = { jamoLen, words };
    return words;
}

function calculateExpectedRemainsFast(guessJamos, candidates, jamoLen) {
    const numPatterns = Math.pow(3, jamoLen);
    let patternCounts = new Int32Array(numPatterns);
    
    for (let i = 0; i < candidates.length; i++) {
        patternCounts[getPatternFast(guessJamos, candidates[i].jamos)]++;
    }
    
    let total = candidates.length;
    if (total === 0) return 0;
    
    let sumSquares = 0;
    for (let i = 0; i < numPatterns; i++) {
        let c = patternCounts[i];
        if (c > 0) sumSquares += c * c;
    }
    return sumSquares / total;
}

function filterCandidatesFast(candidates, guessJamos, hintStr) {
    let hintCode = 0;
    for (let i = 0; i < guessJamos.length; i++) {
        if (hintStr[i] === '노') hintCode += 1 * Math.pow(3, i);
        else if (hintStr[i] === '초') hintCode += 2 * Math.pow(3, i);
    }
    return candidates.filter(cand => getPatternFast(guessJamos, cand.jamos) === hintCode);
}

function getUniqueJamos(jamos) {
    let set = new Set();
    for (let j of jamos) {
        if (j) set.add(j);
    }
    return set;
}

async function solveWordle(history, jamoLen, checkAbort) {
    let candidates = initValidWords(jamoLen);
    const allWords = candidates;
    
    let knownGreen = new Set();
    let knownYellow = new Set();

    for (let i = 0; i < history.length; i++) {
        const entry = history[i];
        const guessJamos = decomposeKoreanWord(entry.word);
        while (guessJamos.length < jamoLen) guessJamos.push('');
        candidates = filterCandidatesFast(candidates, guessJamos.slice(0, jamoLen), entry.hint);
        
        for (let j = 0; j < entry.hint.length; j++) {
            if (entry.hint[j] === '초') knownGreen.add(guessJamos[j]);
            if (entry.hint[j] === '노') knownYellow.add(guessJamos[j]);
        }
    }

    const remainCount = candidates.length;
    if (remainCount === 0) {
        return { success: true, remain_count: 0, recommendations: [], full_list: [] };
    }
    
    // 후보가 1~2개밖에 안 남았을 때는 엔트로피 계산 무의미 (바로 정답 후보를 추천)
    if (remainCount <= 2) {
        const recommendations = candidates.map(c => ({
            word: c.word,
            strategy: "직접 타격 (정답 후보)",
            reason: "남은 정답 후보군이 매우 적으므로, 이 단어를 직접 입력하여 정답을 맞추는 것이 최선입니다.",
            expected_remain: 1
        }));
        return {
            success: true,
            remain_count: remainCount,
            recommendations,
            full_list: candidates.map(c => c.word)
        };
    }

    const MAX_EVAL = 6000; 
    const evalPool = [];
    let evalSet = new Set();
    
    for(let i=0; i<Math.min(allWords.length, MAX_EVAL); i++) {
        evalPool.push(allWords[i]);
        evalSet.add(allWords[i].word);
    }
    for (let c of candidates) {
        if (!evalSet.has(c.word)) {
            evalPool.push(c);
            evalSet.add(c.word);
        }
    }

    let bestOverall = null;
    let bestCandidate = null;
    let bestFiltering = null;
    let bestHardMode = null;
    let bestDiversity = null;

    let minExpected = Infinity;
    let minCandidateExpected = Infinity;
    let minFilteringExpected = Infinity;
    let maxNewJamoScore = -Infinity;
    
    let seenJamos = new Set([...knownGreen, ...knownYellow]);
    for (let i = 0; i < history.length; i++) {
        let guessJamos = decomposeKoreanWord(history[i].word);
        for(let j=0; j<guessJamos.length; j++) if(guessJamos[j]) seenJamos.add(guessJamos[j]);
    }

    let candidateSet = new Set(candidates.map(c => c.word));
    let allEvaluated = [];

    for (let i = 0; i < evalPool.length; i++) {
        if (i % 50 === 0) {
            await new Promise(r => setTimeout(r, 0));
            if (checkAbort && checkAbort()) return { success: false, aborted: true };
        }
        
        let wordObj = evalPool[i];
        let expRemain = calculateExpectedRemainsFast(wordObj.jamos, candidates, jamoLen);
        
        allEvaluated.push({ word: wordObj.word, expected_remain: expRemain });
        let isCandidate = candidateSet.has(wordObj.word);
        
        if (expRemain < minExpected) {
            minExpected = expRemain;
            bestOverall = { word: wordObj.word, expected_remain: expRemain };
        }
        
        if (isCandidate) {
            if (expRemain < minCandidateExpected) {
                minCandidateExpected = expRemain;
                bestHardMode = { word: wordObj.word, expected_remain: expRemain };
            }
            if (!bestCandidate) {
                bestCandidate = { word: wordObj.word, expected_remain: expRemain };
            }
        }
        
        let hasGreen = false;
        for (let j of wordObj.jamos) {
            if (knownGreen.has(j)) {
                hasGreen = true; break;
            }
        }
        if (!hasGreen && expRemain < minFilteringExpected) {
            minFilteringExpected = expRemain;
            bestFiltering = { word: wordObj.word, expected_remain: expRemain };
        }
        
        let uniqueJamos = getUniqueJamos(wordObj.jamos);
        let newJamosCount = 0;
        for (let j of uniqueJamos) {
            if (!seenJamos.has(j)) newJamosCount++;
        }
        let diversityScore = newJamosCount * 100 - expRemain;
        if (diversityScore > maxNewJamoScore) {
            maxNewJamoScore = diversityScore;
            bestDiversity = { word: wordObj.word, expected_remain: expRemain };
        }
    }

    if (!bestFiltering) bestFiltering = bestOverall;
    if (!bestHardMode) bestHardMode = bestOverall;
    if (!bestCandidate) bestCandidate = bestOverall;
    if (!bestDiversity) bestDiversity = bestOverall;

    const rawRecommendations = [
        { obj: bestOverall, strategy: "균형 추천 (최적)", reason: "정보량과 정답 확률을 고려한 수학적 최적의 선택입니다." },
        { obj: bestCandidate, strategy: "직접 타격 (정답 후보)", reason: "남은 정답 후보군 중 가장 유력한 일상 단어입니다." },
        { obj: bestFiltering, strategy: "필터링 (초록 배제)", reason: "확정된 초록색 글자를 제외하고 새로운 글자로 넓게 필터링합니다." },
        { obj: bestHardMode, strategy: "하드 모드 최적", reason: "이전 힌트를 모두 준수하면서 후보군을 가장 많이 줄여줍니다." },
        { obj: bestDiversity, strategy: "자모 다양성 (새 자모)", reason: "아직 사용하지 않은 새로운 자모들을 가장 많이 테스트합니다." }
    ];

    const recommendations = [];
    const usedWords = new Set();
    for (let item of rawRecommendations) {
        if (item.obj && !usedWords.has(item.obj.word)) {
            usedWords.add(item.obj.word);
            recommendations.push({
                word: item.obj.word,
                strategy: item.strategy,
                reason: item.reason,
                expected_remain: Math.round(item.obj.expected_remain * 10) / 10
            });
        }
    }

    if (recommendations.length < 5) {
        allEvaluated.sort((a, b) => a.expected_remain - b.expected_remain);
        let extraIdx = 0;
        while (recommendations.length < 5 && extraIdx < allEvaluated.length) {
            let item = allEvaluated[extraIdx];
            if (!usedWords.has(item.word)) {
                recommendations.push({
                    word: item.word,
                    strategy: "일반 추천",
                    reason: "정보량을 기준으로 계산된 효율적인 단어입니다.",
                    expected_remain: Math.round(item.expected_remain * 10) / 10
                });
                usedWords.add(item.word);
            }
            extraIdx++;
        }
    }

    const full_list = remainCount <= 30 ? candidates.map(c => c.word) : [];

    return {
        success: true,
        remain_count: remainCount,
        recommendations,
        full_list
    };
}
